import React from 'react';
import { BrowserRouter, Route } from 'react-router-dom';
import './App.css';
import Content from './Content/Content';
import Header from './Header/Header';
import Navbar from './Navbar/Navbar';
import NavCard from './NavCard/NavCard';
import NavMassage from './NavMassage/NavMassage';
import NavMedia from './NavMedia/NavMedia';

const App = (props) => {
  return (
    <BrowserRouter>
    <div className='app-wrapper'>
     <Header/>
     <Navbar/>
     <div className='app-wrapper-content'>
       <Route path='/content' render ={ () => <Content massage = {props.post} likesCount = {props.likesCount}/> } />
       <Route path='/navmassage' render ={ () => <NavMassage name={props.name} id={props.id} message={props.message} /> } />
       <Route path='/navcard' render ={ () => <NavCard/> } />
       <Route path='/navmedia' render ={ () => <NavMedia/> } />
     </div>
    </div>
    </BrowserRouter>
  );
}

export default App;
